/** Canonical verification levels for BridgedAI signal envelopes. */
export type VerificationLevel =
  | 'cryptographic_verified'
  | 'provider_authoritative'
  | 'runtime_observed'
  | 'scanner_observed'
  | 'inferred'
  | 'manual'
  | 'demo';

const VALID: ReadonlySet<string> = new Set([
  'cryptographic_verified',
  'provider_authoritative',
  'runtime_observed',
  'scanner_observed',
  'inferred',
  'manual',
  'demo',
]);

export function isVerificationLevel(v: string): v is VerificationLevel {
  return VALID.has(v);
}

export function assertVerificationLevel(v: string): VerificationLevel {
  if (!isVerificationLevel(v)) {
    throw new Error(`Invalid verificationLevel: ${v}`);
  }
  return v;
}
